1	import React from 'react';
2	import readline from 'readline';
3	import { Box, type StdinProps, type BoxProps, Text, useStdin } from 'ink';
4	
5	type ExtractFCProps<T> = T extends React.FunctionComponent<infer P> ? P : never;
6	
7	/**
8	 * Represent props of a <Tab>
9	 */
10	export interface TabProps {
11	  name: string;
12	  children: React.ReactNode;
13	}
14	
15	/**
16	 * A <Tab> component
17	 */
18	// eslint-disable-next-line react/prop-types
19	export const Tab: React.FunctionComponent<TabProps> = ({ children }) => (
20	  <>{children}</>
21	);
22	
23	/**
24	 * Declare how does the keyboard interacts with ink-tab here
25	 */
26	interface KeyMapProps {
27	  useNumbers?: boolean;
28	  useTab?: boolean;
29	  previous?: string[];
30	  next?: string[];
31	}
32	
33	interface RequiredKeyMapProps {
34	  useNumbers: boolean;
35	  useTab: boolean;
36	  previous: string[];
37	  next: string[];
38	}
39	
40	/**
41	 * Props for the <Tabs> component
42	 */
43	export interface TabsProps {
44	  /**
45	   * A function called whenever a tab is changing.
46	   * @param {string} name the name of the tab passed in the `name` prop
47	   * @param {React.Component<TabProps>} activeTab the current active tab component
48	   */
49	  onChange: (name: string, activeTab: React.ReactElement<typeof Tab>) => void;
50	  children: Array<React.ReactElement<typeof Tab>>;
51	  flexDirection?: BoxProps['flexDirection'];
52	  width?: BoxProps['width'];
53	  keyMap?: KeyMapProps;
54	  isFocused?: boolean;
55	  defaultValue?: string;
56	  showIndex?: boolean;
57	  colors?: {
58	    activeTab?: {
59	      color?: ExtractFCProps<typeof Text>['color'];
60	      backgroundColor?: ExtractFCProps<typeof Text>['backgroundColor'];
61	    };
62	  };
63	}
64	interface TabsWithStdinProps extends TabsProps {
65	  isRawModeSupported: boolean;
66	  setRawMode: StdinProps['setRawMode'];
67	  stdin: StdinProps['stdin'];
68	}
69	
70	interface TabsWithStdinState {
71	  activeTab: number;
72	}
73	
74	class TabsWithStdin extends React.Component<
75	  TabsWithStdinProps,
76	  TabsWithStdinState
77	> {
78	  // eslint-disable-next-line react/sort-comp
79	  private readonly defaultKeyMap: RequiredKeyMapProps;
80	
81	  public static defaultProps = {
82	    flexDirection: 'row',
83	    keyMap: null,
84	    isFocused: null, // isFocused is null mean that the focus not handle by ink
85	    defaultValue: null,
86	    showIndex: true,
87	  };
88	
89	  constructor(props: TabsWithStdinProps) {
90	    super(props);
91	
92	    this.handleTabChange = this.handleTabChange.bind(this);
93	    this.handleKeyPress = this.handleKeyPress.bind(this);
94	    this.moveToNextTab = this.moveToNextTab.bind(this);
95	    this.moveToPreviousTab = this.moveToPreviousTab.bind(this);
96	
97	    this.state = {
98	      activeTab: 0,
99	    };
100	
101	    this.defaultKeyMap = {
102	      useNumbers: true,
103	      useTab: true,
104	      previous: [this.isColumn() ? 'up' : 'left'],
105	      next: [this.isColumn() ? 'down' : 'right'],
106	    };
107	  }
108	
109	  componentDidMount(): void {
110	    const { stdin, setRawMode, isRawModeSupported, children, defaultValue } =
111	      this.props;
112	
113	    if (isRawModeSupported) {
114	      // use ink / node `setRawMode` to read key-by-key
115	      setRawMode(true);
116	
117	      readline.emitKeypressEvents(stdin);
118	      stdin.on('keypress', this.handleKeyPress);
119	    }
120	
121	    // select defaultValue if it's valid otherwise select the first tab on component mount
122	    let initialTabIndex = 0;
123	
124	    if (typeof defaultValue !== 'undefined') {
125	      const foundIndex = children.findIndex(
126	        (child) => child.props.name === defaultValue
127	      );
128	
129	      if (foundIndex > 0) {
130	        initialTabIndex = foundIndex;
131	      }
132	    }
133	
134	    this.handleTabChange(initialTabIndex);
135	  }
136	
137	  componentWillUnmount(): void {
138	    const { stdin, setRawMode, isRawModeSupported } = this.props;
139	
140	    if (isRawModeSupported) {
141	      setRawMode(false); // remove set raw mode, as it might interfere with CTRL-C
142	      stdin.removeListener('keypress', this.handleKeyPress);
143	    }
144	  }
145	
146	  handleTabChange(tabId: number): void {
147	    const { children, onChange } = this.props;
148	
149	    const tab = children[tabId];
150	
151	    // eslint-disable-next-line @typescript-eslint/strict-boolean-expressions -- handle possible runtime errors
152	    if (!tab) {
153	      return;
154	    }
155	
156	    this.setState({
157	      activeTab: tabId,
158	    });
159	
160	    onChange(tab.props.name, tab);
161	  }
162	
163	  handleKeyPress(
164	    ch: string,
165	    key: null | { name: string; shift: boolean; meta: boolean }
166	  ): void {
167	    const { keyMap, isFocused } = this.props;
168	
169	    if (key == null || isFocused === false) {
170	      return;
171	    }
172	
173	    const currentKeyMap = { ...this.defaultKeyMap, ...keyMap };
174	    const { useNumbers, useTab, previous, next } = currentKeyMap;
175	
176	    if (previous.some((keyName) => keyName === key.name)) {
177	      this.moveToPreviousTab();
178	    }
179	
180	    if (next.some((keyName) => keyName === key.name)) {
181	      this.moveToNextTab();
182	    }
183	
184	    switch (key.name) {
185	      case 'tab': {
186	        if (!useTab || isFocused !== null) {
187	          // if isFocused != null, then the focus is managed by ink and thus we can not use this key
188	          return;
189	        }
190	
191	        if (key.shift) {
192	          this.moveToPreviousTab();
193	        } else {
194	          this.moveToNextTab();
195	        }
196	
197	        break;
198	      }
199	
200	      case '0':
201	      case '1':
202	      case '2':
203	      case '3':
204	      case '4':
205	      case '5':
206	      case '6':
207	      case '7':
208	      case '8':
209	      case '9': {
210	        if (!useNumbers) {
211	          return;
212	        }
213	        if (key.meta) {
214	          const tabId = key.name === '0' ? 9 : parseInt(key.name, 10) - 1;
215	
216	          this.handleTabChange(tabId);
217	        }
218	
219	        break;
220	      }
221	
222	      default:
223	        break;
224	    }
225	  }
226	
227	  isColumn(): boolean {
228	    const { flexDirection } = this.props;
229	
230	    return flexDirection === 'column' || flexDirection === 'column-reverse';
231	  }
232	
233	  moveToNextTab(): void {
234	    const { children } = this.props;
235	    const { activeTab } = this.state;
236	
237	    let nextTabId = activeTab + 1;
238	    if (nextTabId >= children.length) {
239	      nextTabId = 0;
240	    }
241	
242	    this.handleTabChange(nextTabId);
243	  }
244	
245	  moveToPreviousTab(): void {
246	    const { children } = this.props;
247	    const { activeTab } = this.state;
248	
249	    let nextTabId = activeTab - 1;
250	    if (nextTabId < 0) {
251	      nextTabId = children.length - 1;
252	    }
253	
254	    this.handleTabChange(nextTabId);
255	  }
256	
257	  render(): React.ReactNode {
258	    const {
259	      children,
260	      flexDirection,
261	      width,
262	      isFocused,
263	      showIndex,
264	      colors: colorsProp,
265	      ...rest
266	    } = this.props;
267	    const { activeTab } = this.state;
268	
269	    const separatorWidth = width ?? 6;
270	
271	    const separator = this.isColumn()
272	      ? new Array(separatorWidth).fill('─').join('')
273	      : ' | ';
274	
275	    return (
276	      <Box flexDirection={flexDirection} width={width} {...rest}>
277	        {children.map((child, key) => {
278	          const { name } = child.props;
279	          let colors = {};
280	          if (isFocused !== false) {
281	            colors = {
282	              backgroundColor:
283	                activeTab === key
284	                  ? colorsProp?.activeTab?.color ?? 'green'
285	                  : undefined,
286	              color:
287	                activeTab === key
288	                  ? colorsProp?.activeTab?.backgroundColor ?? 'black'
289	                  : undefined,
290	            };
291	          } else {
292	            colors = {
293	              backgroundColor: activeTab === key ? 'gray' : undefined,
294	              color: activeTab === key ? 'black' : undefined,
295	            };
296	          }
297	
298	          return (
299	            <Box key={name} flexDirection={flexDirection}>
300	              {key !== 0 && <Text color="dim">{separator}</Text>}
301	              <Box>
302	                {showIndex === true && <Text color="grey">{key + 1}. </Text>}
303	                <Text {...colors}>{child}</Text>
304	              </Box>
305	            </Box>
306	          );
307	        })}
308	      </Box>
309	    );
310	  }
311	}
312	
313	/**
314	 * The <Tabs> component
315	 */
316	export const Tabs: React.FunctionComponent<TabsProps> = (props) => {
317	  const { isRawModeSupported, stdin, setRawMode } = useStdin();
318	
319	  return (
320	    <TabsWithStdin
321	      isRawModeSupported={isRawModeSupported}
322	      stdin={stdin}
323	      setRawMode={setRawMode}
324	      {...props}
325	    />
326	  );
327	};
